<template>
    <div class="card my-card">
        <div class="card-body">
            <div class="avatar-container">
                <img src="/avatar-placeholder.svg" 
                     alt="avatar"
                     class="hover-glow img-fluid">
            </div>
            
            <h2 class="cyber-text mb-3">SouthString</h2>
            <p class="bio-text">I am a student at Hangzhou Dianzi University.</p>
            <p class="bio-text">More details coming soon.</p>

            <div class="social-links mt-4">
                <span class="bio-text">Social links will be added later.</span>
            </div>
            <div class="blogroll-container">
                    <div class="blogroll-title cyber-text">
                        Links
                    </div>
                    <div v-for="blog in blogs" class="blogroll" :key="blog.id">
                        <a :href="blog.link" target="_blank" rel="noopener noreferrer">
                            <blogRoll>
                                {{ blog.name }}
                            </blogRoll>
                        </a>
                    </div>
                </div>
        </div>
    </div>
</template>

<script>
import blogRoll from './blogRoll.vue'; 

export default {
    name: 'infoCard',
    components: {
        blogRoll
    }, 
    data() {
      return {
        blogs: [], 
      };
    },
    async mounted() {
      try {
        const response = await fetch('/blogroll/blogroll.json'); 
        if (!response.ok) {
          throw new Error(`HTTP error! status: ${response.status}`);
        }
        this.blogs = await response.json();
      } catch (error) {
        console.error("Failed to load links:", error);
      }
    }
}

</script>

